module packet_filter(  
    input [3:0] packet_type,  
    input enable,  
    output reg obf_allowed  
);  
    always @(*) begin  
        if (enable) begin  
            if (packet_type == 4'b0001)  
                obf_allowed = 1'b1;  
            else  
                obf_allowed = 1'b0;  
        end else begin  
            obf_allowed = 1'b0;  
        end  
    end  
endmodule
